{
  "name": "State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Medicare beneficiaries (age 65+), those under 65 with disabilities, individuals nearing Medicare eligibility, caregivers, family members, and low-income individuals seeking financial help[1][2][3]",
    "asset_limits": "No asset limits or tests apply[1][2][3]",
    "other_requirements": ["Must be a Medicare beneficiary or family/caregiver of one; available statewide in Maryland[1][2][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, confidential, unbiased one-on-one counseling, education, and advocacy including: Medicare plan comparison/enrollment (Parts A/B/C/D), Medigap, prescription drug coverage (Part D), Medicare Advantage, long-term care insurance, billing issues/appeals/denials/grievances, financial assistance programs (MSPs, Extra Help, Medicaid), preventive services, healthcare fraud/abuse detection, community workshops/presentations; no fixed dollar amounts or hours, provided via phone, in-person, or events[1][2][3][4]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: (410) 767-1100 or toll-free 1-800-243-3425 to connect to local SHIP office[3][5][7][9]", "Website: https://aging.maryland.gov/pages/state-health-insurance-program.aspx (includes SHIP Directory for local offices)[3][5]", "In-person or phone via local county offices (e.g., Carroll County: 410-386-3800, 125 Stoner Avenue, Westminster, MD 21157; Prince George's, Anne Arundel, etc.)[1][2][6]", "No formal application form required; contact for counseling appointment[1][2][3]"],
    "processing_time": "Immediate counseling available via phone or in-person; no specified processing delay[1][2][3]",
    "waitlist": null,
    "forms": ["No SHIP-specific forms; for related financial aid: MSP Application (9705-DHS-QMB-SLMB-MSP), Extra Help (SSA i1020), Maryland SPDAP[6]"],
    "documents": ["No documents required for SHIP counseling itself; for assistance programs: Medicare card, income proof, may be requested during session[2][6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; covers all 23 counties and Baltimore City[1][3]",
    "regional_variations": "Delivered through local county offices/providers with same core services; contact central line for local office (e.g., Carroll, Prince George's, Anne Arundel, Montgomery, Frederick have dedicated pages)[1][2][6][8][9]",
    "offices_or_providers": ["Maryland Department of Aging (central): 301 West Preston Street, Room 1007, Baltimore, MD 21201; local offices via https://aging.maryland.gov SHIP Directory[3][5]"]
  },
  "official_source": "https://aging.maryland.gov/pages/state-health-insurance-program.aspx[3][5]",
  "gotchas": ["Not a financial aid or healthcare provider program—only free counseling/education, no direct payments or services; people confuse with Medicare Savings Programs (MSP) or Extra Help, which SHIP helps apply for but does not fund; services are free but require contacting local office as central line connects you; available to under-65 disabled Medicare beneficiaries and pre-eligibility individuals, often overlooked[1][2][3][4]"],
  "data_shape_notes": "no income/asset test; counseling-only service via county network; open to Medicare families/caregivers without enrollment barriers[1][2][3]"
}

{
  "name": "National Family Caregiver Support Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits specified in program guidelines.[1][3][4]",
    "asset_limits": "No asset limits specified; no mention of asset counting or exemptions.[1][3][4]",
    "other_requirements": [
      "Adult family members or other informal caregivers age 18 and older providing care to individuals 60 years of age and older",
      "Adult family members or other informal caregivers age 18 and older providing care to individuals of any age with Alzheimer's disease and related disorders",
      "Grandparents and other relatives (not parents) 55 years of age and older providing care to children under the age of 18",
      "Grandparents and other relatives (not parents) 55 years of age and older providing care to adults age 18-59 with disabilities"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Five specific services: 1) Information to caregivers about available services; 2) Assistance to caregivers in gaining access to services; 3) Individual counseling, organization of support groups, and caregiver training; 4) Respite care; 5) Supplemental services (on a limited basis). No fixed dollar amounts or hours per week specified; services are non-fee based where offered.[1][3][4][7]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": [
      "Contact local Area Agency on Aging (administered by local network); statewide access via Maryland Department of Aging",
      "No specific phone, URL, mail, or in-person details in results; eligibility screenings and application help provided by local providers (e.g., MAC Inc. for certain areas)"
    ],
    "processing_time": "Not specified",
    "waitlist": "Not specified; may vary locally due to limited supplemental services",
    "forms": ["No specific form names or numbers identified"],
    "documents": ["Not specified; prepare proof of caregiver relationship and care recipient details for screening"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered locally by network of Area Agencies on Aging; available across Maryland",
    "regional_variations": "Services delivered by local providers (e.g., MAC Inc., Montgomery County programs); eligibility screenings and access may vary by local Area Agency on Aging; potential differences in availability of supplemental services or wait times by region",
    "offices_or_providers": ["Local Area Agencies on Aging; examples include MAC Inc. and Montgomery County HHS"]
  },
  "official_source": "https://aging.maryland.gov/pages/national-family-caregiver-support.aspx",
  "gotchas": [
    "No income or asset tests, but services like supplemental are limited basis—may not be available to all eligible",
    "Must contact local Area Agency on Aging (not centralized state application); varies by region",
    "Focuses on caregiver support services, not direct financial aid or healthcare to care recipient",
    "Eligibility emphasizes informal/unpaid caregivers; professional caregivers may not qualify"
  ],
  "data_shape_notes": "Administered locally by Area Agencies on Aging with no statewide income/asset tests; services fixed at five types but supplemental limited; eligibility has multiple caregiver categories beyond just elderly care"
}

{
  "name": "Maryland Senior Call Check Program (SCC)",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits; program is free for all eligible Maryland residents[4]",
    "asset_limits": "No asset limits or tests apply[1][2][4]",
    "other_requirements": [
      "Maryland resident[1][2][4]",
      "Has a working landline or cell phone (TTY available); no automated call blocking technology[1][2][3][4]",
      "Must apply on their own behalf; no one else can apply for them[1][2][3]",
      "Highly recommended to have a willing alternate contact person (e.g., adult child, neighbor, loved one)[1][2][3][4]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Daily automated telephone call or text message at a pre-selected time block (8 a.m. to 4 p.m., ideally within one-hour window chosen by participant, such as 8-10 a.m. or 2-4 p.m.). If unanswered after three attempts, calls alternate contact to encourage wellness check. If alternate also unreachable, contacts local non-emergency law enforcement for welfare check. Service is free and first-in-nation statewide program[1][3][4][6]",
    "varies_by": "fixed"
  },
  "application": {
    "methods": [
      "Phone: Toll-free 1-866-50-CHECK (1-866-502-0560), lines open Monday-Friday 8 a.m.-5 p.m., Saturday 9 a.m.-3 p.m.[4]",
      "Online: https://aging.maryland.gov/Pages/senior-call-check-sign-up.aspx[1]",
      "Mail: Download paper application from https://aging.maryland.gov/siteassets/pages/senior-call-check/maryland-senior-call-check-paper-application.pdf and mail to address on form (Baltimore MD 21202)[1]"
    ],
    "processing_time": "Verification and enrollment typically within 24 hours Monday-Saturday; participant informed when daily calls begin[2][5]",
    "waitlist": null,
    "forms": [
      "Maryland Senior Call Check Program Application (paper version available as PDF)[1][2]"
    ],
    "documents": [
      "No specific documents required; provide name, county of residence, address, phone number, date of birth (implied), alternate contact name and phone, preferred call time block, and signature agreeing to terms[1][2][3]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to any Maryland resident meeting eligibility[1][4][6]",
    "regional_variations": "No regional differences noted; statewide program with local law enforcement welfare checks varying by locality only in execution (resources limited)[1][2]",
    "offices_or_providers": null
  },
  "official_source": "https://aging.maryland.gov/pages/senior-call-check.aspx",
  "gotchas": [
    "Must disable automated call blocking on phone and alternate's phone[1][2][4]",
    "Participant must apply themselves; family cannot apply on their behalf[1][2][3]",
    "No guaranteed timely welfare check by law enforcement due to limited resources[1][2]",
    "Age eligibility listed variably as 60 or 65 across sources; official site states 60+[4]; older PDFs say 65[1][2][5]",
    "Alternate contact highly recommended but not strictly required (program may assign one)[4]"
  ],
  "data_shape_notes": "No income or asset test; simple eligibility based on age, residency, and phone access; fixed daily service statewide with no tiers or variations; self-application only"
}
